 14 #ifndef LLVM_SUPPORT_KNOWNFPCLASS_H
 15 #define LLVM_SUPPORT_KNOWNFPCLASS_H
 16 
 17 #include "llvm/ADT/FloatingPointMode.h"
 18 #include "llvm/Support/Compiler.h"
 19 #include <optional>
 20 
 21 namespace llvm {
 22 class APFloat;
 23 
 24 struct KnownFPClass {
 25   /// Floating-point classes the value could be one of.
 26   FPClassTest KnownFPClasses = fcAllFlags;
 27 
 28   /// std::nullopt if the sign bit is unknown, true if the sign bit is
 29   /// definitely set or false if the sign bit is definitely unset.
 30   std::optional<bool> SignBit;
 31 
 32   KnownFPClass() = default;
 33   KnownFPClass(const APFloat &C);
 34 
 35   bool operator==(KnownFPClass Other) const {
 36     return KnownFPClasses == Other.KnownFPClasses && SignBit == Other.SignBit;
 37   }
 38 
 39   /// Return true if it's known this can never be one of the mask entries.
 40   bool isKnownNever(FPClassTest Mask) const {
 41     return (KnownFPClasses & Mask) == fcNone;
 42   }
 43 
 44   bool isKnownAlways(FPClassTest Mask) const { return isKnownNever(~Mask); }
 45 
 46   bool isUnknown() const { return KnownFPClasses == fcAllFlags && !SignBit; }
 47 
 48   /// Return true if it's known this can never be a nan.
 49   bool isKnownNeverNaN() const { return isKnownNever(fcNan); }
 50 
 51   /// Return true if it's known this must always be a nan.
 52   bool isKnownAlwaysNaN() const { return isKnownAlways(fcNan); }
 53 
 54   /// Return true if it's known this can never be an infinity.
 55   bool isKnownNeverInfinity() const { return isKnownNever(fcInf); }
 56 
 57   /// Return true if it's known this can never be +infinity.
 58   bool isKnownNeverPosInfinity() const { return isKnownNever(fcPosInf); }
 59 
 60   /// Return true if it's known this can never be -infinity.
 61   bool isKnownNeverNegInfinity() const { return isKnownNever(fcNegInf); }
 62 
 63   /// Return true if it's known this can never be a subnormal
 64   bool isKnownNeverSubnormal() const { return isKnownNever(fcSubnormal); }
 65 
 66   /// Return true if it's known this can never be a positive subnormal
 67   bool isKnownNeverPosSubnormal() const { return isKnownNever(fcPosSubnormal); }
 68 
 69   /// Return true if it's known this can never be a negative subnormal
 70   bool isKnownNeverNegSubnormal() const { return isKnownNever(fcNegSubnormal); }
 71 
 72   /// Return true if it's known this can never be a zero. This means a literal
 73   /// [+-]0, and does not include denormal inputs implicitly treated as [+-]0.
 74   bool isKnownNeverZero() const { return isKnownNever(fcZero); }
 75 
 76   /// Return true if it's known this can never be a literal positive zero.
 77   bool isKnownNeverPosZero() const { return isKnownNever(fcPosZero); }
 78 
 79   /// Return true if it's known this can never be a negative zero. This means a
 80   /// literal -0 and does not include denormal inputs implicitly treated as -0.
 81   bool isKnownNeverNegZero() const { return isKnownNever(fcNegZero); }
 82 
 83   /// Return true if it's know this can never be interpreted as a zero. This
 84   /// extends isKnownNeverZero to cover the case where the assumed
 85   /// floating-point mode for the function interprets denormals as zero.
 86   LLVM_ABI bool isKnownNeverLogicalZero(DenormalMode Mode) const;
 87 
 88   /// Return true if it's know this can never be interpreted as a negative zero.
 89   LLVM_ABI bool isKnownNeverLogicalNegZero(DenormalMode Mode) const;
 90 
 91   /// Return true if it's know this can never be interpreted as a positive zero.
 92   LLVM_ABI bool isKnownNeverLogicalPosZero(DenormalMode Mode) const;
 93 
 94   static constexpr FPClassTest OrderedLessThanZeroMask =
 95       fcNegSubnormal | fcNegNormal | fcNegInf;
 96   static constexpr FPClassTest OrderedGreaterThanZeroMask =
 97       fcPosSubnormal | fcPosNormal | fcPosInf;
 98 
 99   /// Return true if we can prove that the analyzed floating-point value is
100   /// either NaN or never less than -0.0.
101   ///
102   ///      NaN --> true
103   ///       +0 --> true
104   ///       -0 --> true
105   ///   x > +0 --> true
106   ///   x < -0 --> false
107   bool cannotBeOrderedLessThanZero() const {
108     return isKnownNever(OrderedLessThanZeroMask);
109   }
110 
111   /// Return true if we can prove that the analyzed floating-point value is
112   /// either NaN or never greater than -0.0.
113   ///      NaN --> true
114   ///       +0 --> true
115   ///       -0 --> true
116   ///   x > +0 --> false
117   ///   x < -0 --> true
118   bool cannotBeOrderedGreaterThanZero() const {
119     return isKnownNever(OrderedGreaterThanZeroMask);
120   }
121 
122   KnownFPClass &operator|=(const KnownFPClass &RHS) {
123     KnownFPClasses = KnownFPClasses | RHS.KnownFPClasses;
124 
125     if (SignBit != RHS.SignBit)
126       SignBit = std::nullopt;
127     return *this;
128   }
129 
130   void knownNot(FPClassTest RuleOut) {
131     KnownFPClasses = KnownFPClasses & ~RuleOut;
132     if (isKnownNever(fcNan) && !SignBit) {
133       if (isKnownNever(fcNegative))
134         SignBit = false;
135       else if (isKnownNever(fcPositive))
136         SignBit = true;
137     }
138   }
139 
140   void fneg() {
141     KnownFPClasses = llvm::fneg(KnownFPClasses);
142     if (SignBit)
143       SignBit = !*SignBit;
144   }
145 
146   void fabs() {
147     if (KnownFPClasses & fcNegZero)
148       KnownFPClasses |= fcPosZero;
149 
150     if (KnownFPClasses & fcNegInf)
151       KnownFPClasses |= fcPosInf;
152 
153     if (KnownFPClasses & fcNegSubnormal)
154       KnownFPClasses |= fcPosSubnormal;
155 
156     if (KnownFPClasses & fcNegNormal)
157       KnownFPClasses |= fcPosNormal;
158 
159     signBitMustBeZero();
160   }
161 
162   /// Apply the canonicalize intrinsic to this value. This is essentially a
163   /// stronger form of propagateCanonicalizingSrc.
164   LLVM_ABI static KnownFPClass
165   canonicalize(const KnownFPClass &Src,
166                DenormalMode DenormMode = DenormalMode::getDynamic());
167 
168   /// Report known values for exp, exp2 and exp10.
169   LLVM_ABI static KnownFPClass exp(const KnownFPClass &Src);
170 
171   /// Return true if the sign bit must be 0, ignoring the sign of nans.
172   bool signBitIsZeroOrNaN() const { return isKnownNever(fcNegative); }
173 
174   /// Assume the sign bit is zero.
175   void signBitMustBeZero() {
176     KnownFPClasses &= (fcPositive | fcNan);
177     SignBit = false;
178   }
179 
180   /// Assume the sign bit is one.
181   void signBitMustBeOne() {
182     KnownFPClasses &= (fcNegative | fcNan);
183     SignBit = true;
184   }
185 
186   void copysign(const KnownFPClass &Sign) {
187     // Don't know anything about the sign of the source. Expand the possible set
188     // to its opposite sign pair.
189     if (KnownFPClasses & fcZero)
190       KnownFPClasses |= fcZero;
191     if (KnownFPClasses & fcSubnormal)
192       KnownFPClasses |= fcSubnormal;
193     if (KnownFPClasses & fcNormal)
194       KnownFPClasses |= fcNormal;
195     if (KnownFPClasses & fcInf)
196       KnownFPClasses |= fcInf;
197 
198     // Sign bit is exactly preserved even for nans.
199     SignBit = Sign.SignBit;
200 
201     // Clear sign bits based on the input sign mask.
202     if (Sign.isKnownNever(fcPositive | fcNan) || (SignBit && *SignBit))
203       KnownFPClasses &= (fcNegative | fcNan);
204     if (Sign.isKnownNever(fcNegative | fcNan) || (SignBit && !*SignBit))
205       KnownFPClasses &= (fcPositive | fcNan);
206   }
207 
208   // Propagate knowledge that a non-NaN source implies the result can also not
209   // be a NaN. For unconstrained operations, signaling nans are not guaranteed
210   // to be quieted but cannot be introduced.
211   void propagateNaN(const KnownFPClass &Src, bool PreserveSign = false) {
212     if (Src.isKnownNever(fcNan)) {
213       knownNot(fcNan);
214       if (PreserveSign)
215         SignBit = Src.SignBit;
216     } else if (Src.isKnownNever(fcSNan))
217       knownNot(fcSNan);
218   }
219 
220   /// Propagate knowledge from a source value that could be a denormal or
221   /// zero. We have to be conservative since output flushing is not guaranteed,
222   /// so known-never-zero may not hold.
223   ///
224   /// This assumes a copy-like operation and will replace any currently known
225   /// information.
226   LLVM_ABI void propagateDenormal(const KnownFPClass &Src, DenormalMode Mode);
227 
228   /// Report known classes if \p Src is evaluated through a potentially
229   /// canonicalizing operation. We can assume signaling nans will not be
230   /// introduced, but cannot assume a denormal will be flushed under FTZ/DAZ.
231   ///
232   /// This assumes a copy-like operation and will replace any currently known
233   /// information.
234   LLVM_ABI void propagateCanonicalizingSrc(const KnownFPClass &Src,
235                                            DenormalMode Mode);
236 
237   void resetAll() { *this = KnownFPClass(); }
238 };
239 
240 inline KnownFPClass operator|(KnownFPClass LHS, const KnownFPClass &RHS) {
241   LHS |= RHS;
242   return LHS;
243 }
244 
245 inline KnownFPClass operator|(const KnownFPClass &LHS, KnownFPClass &&RHS) {
246   RHS |= LHS;
247   return std::move(RHS);
248 }
249 
250 } // namespace llvm
